// QRCode.js compatibility shim using qrcode-generator
// Provides same API as qrcodejs but using qrcode-generator

(function (global) {
  'use strict';

  var QRCode = function (el, opts) {
    if (typeof opts === 'string') {
      opts = { text: opts };
    }

    this._el = typeof el === 'string' ? document.getElementById(el) : el;
    this._opts = Object.assign({
      width: 128,
      height: 128,
      colorDark: '#000000',
      colorLight: '#ffffff',
      correctLevel: 2, // M
      text: '',
    }, opts);

    this._render();
  };

  // Map correctLevel numbers to qrcode-generator letters
  QRCode._levelMap = { 1: 'L', 0: 'L', 2: 'M', 3: 'Q', 4: 'H' };

  QRCode.CorrectLevel = { L: 1, M: 2, Q: 3, H: 4 };

  QRCode.prototype._render = function () {
    var el = this._el;
    var opts = this._opts;

    // Clear
    while (el.firstChild) el.removeChild(el.firstChild);

    var levelKey = QRCode._levelMap[opts.correctLevel] || 'M';
    var text = opts.text || '';

    // Use qrcode-generator
    var typeNumber = 0; // auto
    var qr = qrcode(typeNumber, levelKey);
    qr.addData(text);
    qr.make();

    var moduleCount = qr.getModuleCount();
    var canvas = document.createElement('canvas');
    canvas.width = opts.width;
    canvas.height = opts.height;
    var ctx = canvas.getContext('2d');

    var cellSize = opts.width / moduleCount;

    // Background
    ctx.fillStyle = opts.colorLight;
    ctx.fillRect(0, 0, opts.width, opts.height);

    // Modules
    ctx.fillStyle = opts.colorDark;
    for (var row = 0; row < moduleCount; row++) {
      for (var col = 0; col < moduleCount; col++) {
        if (qr.isDark(row, col)) {
          ctx.fillRect(
            Math.floor(col * cellSize),
            Math.floor(row * cellSize),
            Math.ceil(cellSize),
            Math.ceil(cellSize)
          );
        }
      }
    }

    el.appendChild(canvas);
  };

  QRCode.prototype.makeCode = function (text) {
    this._opts.text = text;
    this._render();
  };

  QRCode.prototype.makeImage = function () {};
  QRCode.prototype.clear = function () {
    while (this._el.firstChild) this._el.removeChild(this._el.firstChild);
  };

  global.QRCode = QRCode;

})(window);
